// menu.js - كود واحد كامل
import { useState, useEffect } from "react";

export default function Menu() {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });
  const [textIndex, setTextIndex] = useState(0);
  
  const texts = ["مرحباً", "أهلاً", "تفضلوا", "استمتعوا"];

  // 4 كاردات فقط - أحجام كبيرة جداً
  const cards = [
    { id: 1, name: "شيشة", icon: "💨", color: "#ff6b6b", size: 220, top: "8%", left: "2%", rotate: -6, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
    { id: 2, name: "أكل", icon: "🍔", color: "#4ecdc4", size: 200, bottom: "5%", left: "3%", rotate: 4, image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png" },
    { id: 3, name: "مشروبات", icon: "🥤", color: "#45b7d1", size: 210, top: "12%", right: "2%", rotate: -4, image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png" },
    { id: 4, name: "ديسار", icon: "🍰", color: "#f9ca24", size: 195, bottom: "8%", right: "3%", rotate: 5, image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png" }
  ];

  // تغيير النص في المنتصف
  useEffect(() => {
    const interval = setInterval(() => {
      setTextIndex((prev) => (prev + 1) % texts.length);
    }, 2500);
    return () => clearInterval(interval);
  }, []);

  // حركة الماوس
  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth - 0.5) * 40,
        y: (e.clientY / window.innerHeight - 0.5) * 40
      });
    };
    window.addEventListener("mousemove", handleMouseMove);
    return () => window.removeEventListener("mousemove", handleMouseMove);
  }, []);

  const handleCardClick = (cardName) => {
    alert(`✨ لقد اخترت: ${cardName} ✨`);
  };

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(135deg, #0a0a1a, #1a1a3a, #0d0d2a)",
      position: "relative",
      overflow: "hidden",
      fontFamily: "sans-serif"
    }}>
      
      {/* خلفية متحركة */}
      <div style={{
        position: "absolute",
        width: "100%",
        height: "100%",
        background: "radial-gradient(circle at 50% 50%, rgba(34,197,94,0.08) 0%, transparent 70%)",
        pointerEvents: "none"
      }}></div>

      {/* الكاردات الأربعة الكبيرة - في الخلفية */}
      {cards.map((card) => (
        <div
          key={card.id}
          onClick={() => handleCardClick(card.name)}
          style={{
            position: "fixed",
            top: card.top,
            left: card.left,
            right: card.right,
            bottom: card.bottom,
            transform: `
              translate(
                ${mousePosition.x * (card.id % 2 === 0 ? 0.6 : -0.5)}px, 
                ${mousePosition.y * (card.id % 2 === 0 ? -0.5 : 0.6)}px
              ) 
              rotate(${card.rotate}deg)
            `,
            transition: "transform 0.2s ease-out",
            zIndex: 5,
            cursor: "pointer"
          }}
        >
          <div style={{
            background: `linear-gradient(135deg, ${card.color}, ${card.color}99)`,
            width: `${card.size}px`,
            padding: "35px 20px",
            borderRadius: "45px",
            textAlign: "center",
            boxShadow: "0 30px 60px rgba(0,0,0,0.5)",
            backdropFilter: "blur(12px)",
            border: "2px solid rgba(255,255,255,0.25)",
            transition: "all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275)"
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.transform = `scale(1.1) rotate(${card.rotate + 8}deg)`;
            e.currentTarget.style.boxShadow = "0 45px 80px rgba(0,0,0,0.6)";
            e.currentTarget.style.border = "2px solid rgba(34,197,94,0.9)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.transform = "scale(1) rotate(0deg)";
            e.currentTarget.style.boxShadow = "0 30px 60px rgba(0,0,0,0.5)";
            e.currentTarget.style.border = "2px solid rgba(255,255,255,0.25)";
          }}
          >
            <img 
              src={card.image} 
              alt={card.name} 
              style={{ 
                width: "100px", 
                height: "100px", 
                marginBottom: "15px", 
                filter: "drop-shadow(2px 4px 12px black)" 
              }} 
            />
            <h3 style={{ 
              color: "white", 
              margin: "12px 0 8px", 
              fontSize: "2rem", 
              fontWeight: "bold" 
            }}>{card.name}</h3>
            <span style={{ fontSize: "3rem" }}>{card.icon}</span>
          </div>
        </div>
      ))}

      {/* كلمة MONO في المنتصف - كبيرة جداً باللون الأخضر فقط */}
      <div style={{
        position: "fixed",
        top: "50%",
        left: "50%",
        transform: `translate(-50%, -50%) translate(${mousePosition.x * 0.15}px, ${mousePosition.y * 0.15}px)`,
        textAlign: "center",
        zIndex: 20,
        transition: "transform 0.15s ease-out",
        pointerEvents: "none"
      }}>
        <h1 style={{
          fontSize: "8rem",
          fontWeight: "900",
          color: "#22c55e",
          margin: 0,
          letterSpacing: "8px",
          textShadow: "0 0 30px rgba(34,197,94,0.5), 0 0 60px rgba(34,197,94,0.3)",
          whiteSpace: "nowrap"
        }}>
          {texts[textIndex]}
        </h1>
        <div style={{
          width: "150px",
          height: "4px",
          background: "linear-gradient(90deg, #22c55e, #4ade80, #22c55e)",
          margin: "30px auto 0",
          borderRadius: "10px"
        }}></div>
      </div>

      {/* نص سفلي */}
      <div style={{
        position: "fixed",
        bottom: "25px",
        left: "0",
        right: "0",
        textAlign: "center",
        color: "rgba(255,255,255,0.25)",
        fontSize: "14px",
        zIndex: 30,
        pointerEvents: "none",
        letterSpacing: "1px"
      }}>
        ✨ اضغط على أي كارد لاختيار المنتج ✨
      </div>
    </div>
  );
}
